// Simple placeholder screen (not generated by SquareLine)

#include "../ui.h"
#include "../ui_nav.h"
#include "../ui_gesture_nav.h"
#include "rainmaker_app_backend.h"
#include <stdio.h>

lv_obj_t *ui_Screen_Automations = NULL;

static lv_obj_t *s_autom_top_title = NULL;
static lv_obj_t *s_autom_empty_title = NULL;
static lv_obj_t *s_autom_empty_sub = NULL;
static lv_obj_t *s_autom_add_btn_lab = NULL;

static void ui_automations_msgbox_btn_cb(lv_event_t *e)
{
#if LVGL_VERSION_MAJOR >= 9
    if (lv_event_get_code(e) != LV_EVENT_CLICKED) {
        return;
    }
#else
    if (lv_event_get_code(e) != LV_EVENT_VALUE_CHANGED) {
        return;
    }
#endif
    lv_obj_t *mbox = (lv_obj_t *)lv_event_get_user_data(e);
    if (mbox) {
        lv_msgbox_close_async(mbox);
    }
}

static void ui_automations_show_info(const char *text)
{
    if (text == NULL || text[0] == '\0') {
        text = ui_str(UI_STR_NOT_IMPLEMENTED);
    }
#if LVGL_VERSION_MAJOR >= 9
    lv_obj_t *mbox = lv_msgbox_create(NULL);
    lv_msgbox_add_title(mbox, ui_str(UI_STR_AUTOMATIONS_TITLE));
    lv_msgbox_add_text(mbox, text);
    lv_msgbox_add_close_button(mbox);
    lv_obj_t *ok_btn = lv_msgbox_add_footer_button(mbox, ui_str(UI_STR_OK));
    ui_msgbox_apply_common_layout(mbox);
    if (ok_btn) {
        lv_obj_add_event_cb(ok_btn, ui_automations_msgbox_btn_cb, LV_EVENT_CLICKED, mbox);
    }
#else
    const char *btns[] = { ui_str(UI_STR_OK), "" };
    lv_obj_t *mbox = lv_msgbox_create(NULL, ui_str(UI_STR_AUTOMATIONS_TITLE), text, btns, true);
    ui_msgbox_apply_common_layout(mbox);
    lv_obj_t *btnm = lv_msgbox_get_btns(mbox);
    if (btnm) {
        lv_obj_add_event_cb(btnm, ui_automations_msgbox_btn_cb, LV_EVENT_VALUE_CHANGED, mbox);
    }
#endif
}

static void ui_automations_show_error(const char *reason)
{
    if (reason == NULL || reason[0] == '\0') {
        reason = ui_str(UI_STR_OPERATION_FAILED);
    }
#if LVGL_VERSION_MAJOR >= 9
    lv_obj_t *mbox = lv_msgbox_create(NULL);
    lv_msgbox_add_title(mbox, ui_str(UI_STR_AUTOMATIONS_TITLE));
    lv_msgbox_add_text(mbox, reason);
    lv_msgbox_add_close_button(mbox);
    lv_obj_t *ok_btn = lv_msgbox_add_footer_button(mbox, ui_str(UI_STR_OK));
    ui_msgbox_apply_common_layout(mbox);
    if (ok_btn) {
        lv_obj_add_event_cb(ok_btn, ui_automations_msgbox_btn_cb, LV_EVENT_CLICKED, mbox);
    }
#else
    const char *btns[] = { ui_str(UI_STR_OK), "" };
    lv_obj_t *mbox = lv_msgbox_create(NULL, ui_str(UI_STR_AUTOMATIONS_TITLE), reason, btns, true);
    ui_msgbox_apply_common_layout(mbox);
    lv_obj_t *btnm = lv_msgbox_get_btns(mbox);
    if (btnm) {
        lv_obj_add_event_cb(btnm, ui_automations_msgbox_btn_cb, LV_EVENT_VALUE_CHANGED, mbox);
    }
#endif
}

static void ui_automations_add_event_cb(lv_event_t *e)
{
    if (lv_event_get_code(e) != LV_EVENT_CLICKED) {
        return;
    }
    bool ok = rm_app_backend_add_automations();
    if (!ok) {
        ui_automations_show_error(ui_str(UI_STR_FAILED_ADD_AUTOMATION));
        return;
    }
    printf("Add Automation OK\n");
    ui_automations_show_info(ui_str(UI_STR_AUTOMATIONS_ADD_STUB));
}

static lv_obj_t *ui_automations_create_top_bar(lv_obj_t *parent)
{
    lv_obj_t *bar = lv_obj_create(parent);
    lv_obj_clear_flag(bar, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_set_width(bar, lv_pct(100));
    lv_obj_set_height(bar, ui_display_top_bar_height());
    lv_obj_align(bar, LV_ALIGN_TOP_MID, 0, 0);
    lv_obj_set_style_bg_color(bar, lv_color_hex(0xF5F8FF), 0);
    lv_obj_set_style_border_width(bar, 0, 0);
    lv_obj_set_style_pad_left(bar, ui_display_scale_px(18), 0);
    lv_obj_set_style_pad_right(bar, ui_display_scale_px(18), 0);
    lv_obj_set_style_pad_top(bar, ui_display_scale_px(14), 0);
    lv_obj_set_style_pad_bottom(bar, ui_display_scale_px(10), 0);

    lv_obj_t *title = lv_label_create(bar);
    s_autom_top_title = title;
    lv_label_set_text(title, ui_str(UI_STR_AUTOMATIONS_TITLE));
    lv_obj_set_style_text_font(title, ui_font_title(), 0);
    lv_obj_align(title, LV_ALIGN_TOP_MID, 0, ui_display_scale_px(4));

    /* Add button (top-right) */
    lv_obj_t *add_btn = lv_btn_create(bar);
    lv_obj_clear_flag(add_btn, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_set_size(add_btn, ui_display_scale_px(40), ui_display_scale_px(40));
    lv_obj_align(add_btn, LV_ALIGN_TOP_RIGHT, 0, 0);
    lv_obj_set_style_bg_opa(add_btn, LV_OPA_0, 0);
    lv_obj_set_style_border_width(add_btn, 0, 0);
    lv_obj_set_style_shadow_width(add_btn, 0, 0);
    lv_obj_add_event_cb(add_btn, ui_automations_add_event_cb, LV_EVENT_CLICKED, NULL);

    lv_obj_t *plus = lv_label_create(add_btn);
    lv_label_set_text(plus, LV_SYMBOL_PLUS);
    lv_obj_set_style_text_font(plus, &lv_font_montserrat_26, 0);
    lv_obj_set_style_text_color(plus, lv_color_hex(0x2E6BE6), 0);
    lv_obj_center(plus);

    return bar;
}

void ui_Screen_Automations_screen_init(void)
{
    ui_Screen_Automations = lv_obj_create(NULL);
    /* Keep the top bar fixed; scroll the content area instead */
    lv_obj_clear_flag(ui_Screen_Automations, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_set_style_bg_color(ui_Screen_Automations, lv_color_hex(0xF5F8FF), 0);
    ui_gesture_nav_enable(ui_Screen_Automations);

    (void)ui_automations_create_top_bar(ui_Screen_Automations);

    /* Scrollable content area below the top bar */
    int32_t yres = 240;
    lv_disp_t *disp = lv_disp_get_default();
    if (disp) {
        yres = lv_disp_get_ver_res(disp);
    }
    const int32_t top_h = ui_display_top_bar_height();

    lv_obj_t *content = lv_obj_create(ui_Screen_Automations);
    lv_obj_set_style_bg_opa(content, LV_OPA_0, 0);
    lv_obj_set_style_border_width(content, 0, 0);
    lv_obj_set_style_pad_all(content, 0, 0);
    lv_obj_set_width(content, lv_pct(100));
    lv_obj_set_height(content, LV_MAX(40, yres - top_h));
    lv_obj_align(content, LV_ALIGN_TOP_MID, 0, top_h);
    lv_obj_add_flag(content, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_set_scroll_dir(content, LV_DIR_VER);
    lv_obj_set_scrollbar_mode(content, LV_SCROLLBAR_MODE_OFF);
    /* Allow swipe gesture to bubble up to the screen for page switching */
    lv_obj_add_flag(content, LV_OBJ_FLAG_GESTURE_BUBBLE);

    /* Layout: icon + texts + spacer + bottom button */
    lv_obj_set_flex_flow(content, LV_FLEX_FLOW_COLUMN);
    lv_obj_set_flex_align(content, LV_FLEX_ALIGN_START, LV_FLEX_ALIGN_CENTER, LV_FLEX_ALIGN_CENTER);
    lv_obj_set_style_pad_top(content, ui_display_scale_px(14), 0);
    lv_obj_set_style_pad_bottom(content, ui_display_scale_px(14), 0);
    lv_obj_set_style_pad_row(content, ui_display_scale_px(10), 0);

    lv_obj_t *icon_bg = lv_obj_create(content);
    lv_obj_clear_flag(icon_bg, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_set_size(icon_bg, ui_display_scale_px(74), ui_display_scale_px(74));
    lv_obj_set_style_radius(icon_bg, ui_display_scale_px(37), 0);
    lv_obj_set_style_bg_color(icon_bg, lv_color_hex(0xFFFFFF), 0);
    lv_obj_set_style_border_width(icon_bg, 0, 0);
    lv_obj_set_style_shadow_width(icon_bg, 0, 0);

    lv_obj_t *icon = lv_label_create(icon_bg);
    lv_label_set_text(icon, LV_SYMBOL_CHARGE);
    lv_obj_set_style_text_font(icon, &lv_font_montserrat_30, 0);
    lv_obj_set_style_text_color(icon, lv_color_hex(0x2E6BE6), 0);
    lv_obj_center(icon);

    lv_obj_t *t1 = lv_label_create(content);
    s_autom_empty_title = t1;
    lv_label_set_text(t1, ui_str(UI_STR_AUTOMATIONS_EMPTY));
    lv_obj_set_style_text_font(t1, ui_font_title(), 0);
    lv_obj_set_style_text_color(t1, lv_color_hex(0x2B2B2B), 0);

    lv_obj_t *t2 = lv_label_create(content);
    s_autom_empty_sub = t2;
    lv_label_set_text(t2, ui_str(UI_STR_AUTOMATIONS_EMPTY_SUB));
    lv_obj_set_style_text_font(t2, ui_font_body(), 0);
    lv_obj_set_style_text_color(t2, lv_color_hex(0x7B879C), 0);
    lv_obj_set_style_text_align(t2, LV_TEXT_ALIGN_CENTER, 0);

    /* Spacer to push the button towards the bottom */
    lv_obj_t *spacer = lv_obj_create(content);
    lv_obj_set_size(spacer, 1, 1);
    lv_obj_set_style_bg_opa(spacer, LV_OPA_0, 0);
    lv_obj_set_style_border_width(spacer, 0, 0);
    lv_obj_set_flex_grow(spacer, 1);
    lv_obj_clear_flag(spacer, LV_OBJ_FLAG_SCROLLABLE);

    lv_obj_t *btn = lv_btn_create(content);
    lv_obj_clear_flag(btn, LV_OBJ_FLAG_SCROLLABLE);
    lv_obj_set_width(btn, lv_pct(88));
    lv_obj_set_height(btn, ui_display_scale_px(52));
    lv_obj_set_style_radius(btn, ui_display_scale_px(16), 0);
    lv_obj_set_style_bg_color(btn, lv_color_hex(0x2E5EA7), 0);
    lv_obj_set_style_border_width(btn, 0, 0);
    lv_obj_set_style_shadow_width(btn, 0, 0);
    lv_obj_add_event_cb(btn, ui_automations_add_event_cb, LV_EVENT_CLICKED, NULL);

    lv_obj_t *btn_lab = lv_label_create(btn);
    s_autom_add_btn_lab = btn_lab;
    lv_label_set_text(btn_lab, ui_str(UI_STR_ADD_AUTOMATION));
    lv_obj_set_style_text_color(btn_lab, lv_color_hex(0xFFFFFF), 0);
    lv_obj_set_style_text_font(btn_lab, ui_font_body(), 0);
    lv_obj_center(btn_lab);

    /* Bottom nav removed: swipe left/right to switch screens */
}

void ui_Screen_Automations_screen_destroy(void)
{
    if (ui_Screen_Automations) {
        lv_obj_del(ui_Screen_Automations);
    }
    ui_Screen_Automations = NULL;
    s_autom_top_title = NULL;
    s_autom_empty_title = NULL;
    s_autom_empty_sub = NULL;
    s_autom_add_btn_lab = NULL;
}

void ui_Screen_Automations_apply_language(void)
{
    if (s_autom_top_title) {
        lv_label_set_text(s_autom_top_title, ui_str(UI_STR_AUTOMATIONS_TITLE));
        lv_obj_set_style_text_font(s_autom_top_title, ui_font_title(), 0);
    }
    if (s_autom_empty_title) {
        lv_label_set_text(s_autom_empty_title, ui_str(UI_STR_AUTOMATIONS_EMPTY));
        lv_obj_set_style_text_font(s_autom_empty_title, ui_font_title(), 0);
    }
    if (s_autom_empty_sub) {
        lv_label_set_text(s_autom_empty_sub, ui_str(UI_STR_AUTOMATIONS_EMPTY_SUB));
        lv_obj_set_style_text_font(s_autom_empty_sub, ui_font_body(), 0);
    }
    if (s_autom_add_btn_lab) {
        lv_label_set_text(s_autom_add_btn_lab, ui_str(UI_STR_ADD_AUTOMATION));
        lv_obj_set_style_text_font(s_autom_add_btn_lab, ui_font_body(), 0);
    }
}
